import type { Metadata } from 'next';

export const metadata: Metadata = {
  title: 'Admin Product Catalog',
  description: 'Fast cached product browsing with background catalog sync'
};

export default function RootLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}


// app/page.tsx
import { getAllProducts, syncProducts } from '@/lib/db';

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', gap: '1rem', alignItems: 'start', marginBottom: '1.5rem' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '2rem' }}>Admin Product Catalog</h1>
          <p style={{ margin: '0.5rem 0 0', color: '#555' }}>
            Cached for fast browsing and refreshed in the background when ERP/PIM data changes.
          </p>
        </div>

        <form action={syncProducts}>
          <button
            type="submit"
            style={{
              background: '#111827',
              color: 'white',
              border: 'none',
              borderRadius: '0.5rem',
              padding: '0.75rem 1rem',
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </header>

      <section>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ textAlign: 'left', borderBottom: '1px solid #e5e7eb' }}>
              <th style={{ padding: '0.75rem 0' }}>ID</th>
              <th style={{ padding: '0.75rem 0' }}>Product</th>
              <th style={{ padding: '0.75rem 0' }}>Price</th>
              <th style={{ padding: '0.75rem 0' }}>Inventory</th>
              <th style={{ padding: '0.75rem 0' }}>Availability</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderBottom: '1px solid #f3f4f6' }}>
                <td style={{ padding: '0.75rem 0' }}>{product.id}</td>
                <td style={{ padding: '0.75rem 0', fontWeight: 500 }}>{product.name}</td>
                <td style={{ padding: '0.75rem 0' }}>${product.price}</td>
                <td style={{ padding: '0.75rem 0' }}>{product.inventory}</td>
                <td style={{ padding: '0.75rem 0' }}>{product.availability}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </main>
  );
}


// lib/db.js
import { unstable_cache, revalidateTag } from 'next/cache';

const seedProducts = [
  { id: 1, name: 'Laptop', price: 999, inventory: 12, availability: 'In stock' },
  { id: 2, name: 'Phone', price: 699, inventory: 34, availability: 'In stock' },
  { id: 3, name: 'Tablet', price: 499, inventory: 8, availability: 'Low stock' },
  { id: 4, name: 'Headphones', price: 199, inventory: 0, availability: 'Out of stock' },
  { id: 5, name: 'Watch', price: 299, inventory: 19, availability: 'In stock' }
];

async function fetchProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));
  return seedProducts;
}

export const getAllProducts = unstable_cache(fetchProducts, ['products'], {
  tags: ['products'],
  revalidate: 3600
});

export async function syncProducts() {
  'use server';
  revalidateTag('products');
}


